/*
仕様:
  Excalibur起動中に重ねる、クリック画面遷移確認用のDOM UIを生成する。

役割:
  - 1920x1080基準の固定レイアウトで画面モックを表示する。
  - ボタンクリックで画面IDを切り替える。
  - URLクエリ `?screen=画面ID` へ現在画面を反映する。

更新時の注意:
  このDOMはデザイン確認用の仮UIであり、本物のセーブやラン進行は実装しない。
*/
import "./screenFlow.css";
import { SCREEN_IDS, type ScreenId } from "./screenIds";
import { getScreenDefinition } from "./screenFlow";

type CreateScreenFlowMockOptions = {
  readonly initialScreenId: ScreenId;
  readonly onScreenChange?: (screenId: ScreenId) => void;
};

const ROOT_ID = "screen-flow-mock-root";

export function createScreenFlowMock(options: CreateScreenFlowMockOptions): () => void {
  document.getElementById(ROOT_ID)?.remove();

  const root = document.createElement("div");
  root.id = ROOT_ID;
  root.className = "screen-flow-root";
  document.body.appendChild(root);

  let currentScreenId = options.initialScreenId;

  const navigate = (screenId: ScreenId): void => {
    currentScreenId = screenId;
    render();
    updateUrl(screenId);
    options.onScreenChange?.(screenId);
  };

  const render = (): void => {
    const definition = getScreenDefinition(currentScreenId);
    const transitions =
      definition.id === "debug_menu"
        ? SCREEN_IDS.filter((screenId) => screenId !== "debug_menu").map((screenId) => ({
            label: screenId,
            target: screenId,
          }))
        : definition.transitions;

    root.innerHTML = `
      <main class="screen-flow-frame" aria-label="画面遷移モック">
        <header class="screen-flow-header">
          <div>
            <p class="screen-flow-kicker">P0008 / click screen flow mock</p>
            <h1>${escapeHtml(definition.title)}</h1>
          </div>
          <button class="screen-flow-debug-button" type="button" data-screen-target="debug_menu">debug</button>
        </header>
        <section class="screen-flow-card">
          <p class="screen-flow-id">${escapeHtml(definition.id)}</p>
          <p class="screen-flow-purpose">${escapeHtml(definition.purpose)}</p>
          <ul class="screen-flow-body">
            ${definition.body.map((line) => `<li>${escapeHtml(line)}</li>`).join("")}
          </ul>
        </section>
        <nav class="screen-flow-actions" aria-label="遷移先">
          ${transitions
            .map(
              (transition) => `
            <button class="screen-flow-action" type="button" data-screen-target="${transition.target}">
              <span>${escapeHtml(transition.label)}</span>
              <small>${escapeHtml(transition.target)}</small>
            </button>
          `,
            )
            .join("")}
        </nav>
      </main>
    `;

    root.querySelectorAll<HTMLButtonElement>("[data-screen-target]").forEach((button) => {
      button.addEventListener("click", () => {
        const target = button.dataset.screenTarget;
        if (isKnownScreenId(target)) {
          navigate(target);
        }
      });
    });
  };

  render();
  options.onScreenChange?.(currentScreenId);

  return () => {
    root.remove();
  };
}

function updateUrl(screenId: ScreenId): void {
  const url = new URL(window.location.href);
  url.searchParams.set("screen", screenId);
  window.history.replaceState({}, "", url);
}

function isKnownScreenId(value: string | undefined): value is ScreenId {
  return SCREEN_IDS.some((screenId) => screenId === value);
}

function escapeHtml(value: string): string {
  return value
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}
