/*
仕様:
  `docs/spec/04_ui_flow_screens.md` の画面IDをTypeScript側で一元管理する。

役割:
  - クリック遷移モックで使用する画面IDの正規リストを提供する。
  - テストで画面遷移定義のtypoを検出できるようにする。

更新時の注意:
  仕様書の画面ID変更時は、このリストと tests/ui/screenFlow.test.ts を同時に更新する。
*/
export const SCREEN_IDS = [
  "title",
  "main_menu",
  "scenario_select",
  "run_confirm",
  "phase_hub",
  "normal_event",
  "phase_result",
  "companion_manage",
  "companion_swap",
  "track_select",
  "minigame_start",
  "brave_td",
  "elegant_rhythm",
  "mystic_puzzle",
  "minigame_result",
  "collection",
  "tips",
  "settings",
  "options_menu",
  "debug_menu",
] as const;

export type ScreenId = (typeof SCREEN_IDS)[number];

const SCREEN_ID_SET = new Set<string>(SCREEN_IDS);

export function isScreenId(value: string | null | undefined): value is ScreenId {
  return typeof value === "string" && SCREEN_ID_SET.has(value);
}
