/*
仕様:
  画面一覧と画面遷移を、クリック確認用の軽量データとして定義する。

役割:
  - 主要画面の表示名、説明、次遷移を保持する。
  - URL `?screen=画面ID` による初期表示指定を扱う。
  - 本物のセーブ復帰やラン進行ではなく、画面デザイン確認用の仮遷移だけを扱う。

更新時の注意:
  `saved_run_resume` は画面IDではなく復帰処理名のため、モックでは phase_hub へ仮遷移させる。
*/
import { isScreenId, type ScreenId } from "./screenIds";

export type ScreenTransition = {
  readonly label: string;
  readonly target: ScreenId;
  readonly note?: string;
};

export type ScreenDefinition = {
  readonly id: ScreenId;
  readonly title: string;
  readonly purpose: string;
  readonly body: readonly string[];
  readonly transitions: readonly ScreenTransition[];
};

